using System;
using System.Linq;
using System.Reflection;
using Microsoft.Agents.AI;

// Find AgentResponse in any loaded assembly
var method = typeof(ChatClientAgent).GetMethod("RunAsync", new[] { typeof(string), typeof(AgentSession), typeof(ChatClientAgentRunOptions), typeof(System.Threading.CancellationToken) });
if (method != null)
{
    var returnType = method.ReturnType;
    Console.WriteLine($"Return type: {returnType.FullName}");
    if (returnType.IsGenericType)
    {
        var innerType = returnType.GetGenericArguments()[0];
        Console.WriteLine($"Inner type: {innerType.FullName}");
        foreach (var p in innerType.GetProperties(BindingFlags.Public | BindingFlags.Instance))
            Console.WriteLine($"  PROP: {p.PropertyType.Name} {p.Name}");
        foreach (var m2 in innerType.GetMethods(BindingFlags.Public | BindingFlags.Instance | BindingFlags.DeclaredOnly).Where(m2 => !m2.IsSpecialName))
            Console.WriteLine($"  METHOD: {m2.Name}");
    }
}

// Also check AgentSession
Console.WriteLine("\nAgentSession:");
foreach (var p in typeof(AgentSession).GetProperties(BindingFlags.Public | BindingFlags.Instance))
    Console.WriteLine($"  PROP: {p.PropertyType.Name} {p.Name}");

// Check AgentRunOptions (base of ChatClientAgentRunOptions)
Console.WriteLine("\nAgentRunOptions (base):");
var baseType = typeof(ChatClientAgentRunOptions).BaseType;
if (baseType != null)
{
