using System.ComponentModel;
using System.Net;
using System.Text;
using System.Text.RegularExpressions;
using Microsoft.Agents.AI;
using Microsoft.Extensions.AI;
using Microsoft.Extensions.Logging;
using OpenAI;

// ── Configuration ──────────────────────────────────────────────────────────────

var apiKey = Environment.GetEnvironmentVariable("OPENAI_API_KEY")
    ?? throw new InvalidOperationException(
        "Set the OPENAI_API_KEY environment variable to run this app.");

const string ModelId = "gpt-4o-mini-2024-07-18";

// ── Shared state for the note-taking tool ──────────────────────────────────────

var notebook = new ResearchNotebook();

// ── Build the IChatClient pipeline ─────────────────────────────────────────────

var openAiClient = new OpenAIClient(apiKey);

IChatClient chatClient = openAiClient
    .AsChatClient(ModelId)
    .AsBuilder()
    .UseFunctionInvocation(o => o.MaximumIterationsPerRequest = 10)
    .Build();

// ── Define agent tools ─────────────────────────────────────────────────────────

var tools = new List<AITool>
{
    AIFunctionFactory.Create(
        ([Description("The search query to look up on the web")] string query) =>
            WebSearchTool.SearchAsync(query),
        "SearchWeb",
        "Searches the web for information about a query and returns relevant snippets. " +
        "Use this to gather facts about the research topic."),

    AIFunctionFactory.Create(
        (
            [Description("Short title for the note")] string title,
            [Description("Detailed content of the note")] string content
        ) =>
        {
            notebook.SaveNote(title, content);
            return $"Note saved: \"{title}\"";
        },
        "SaveNote",
        "Saves a research note with a title and detailed content. " +
        "Use this to record important findings during research."),

    AIFunctionFactory.Create(
        () => notebook.GetAllNotes(),
        "GetNotes",
        "Retrieves all previously saved research notes. " +
        "Use this to review what has been gathered so far before writing a summary."),
};

// ── Create the ChatClientAgent ─────────────────────────────────────────────────

var agent = new ChatClientAgent(
    chatClient,
    new ChatClientAgentOptions
    {
        Name = "ResearchAgent",
        Description = "An AI agent that researches topics by searching the web and taking notes.",
        ChatOptions = new ChatOptions
        {
            Temperature = 0f,
            MaxOutputTokens = 2048,
            Tools = tools,
        },
    });

// ── Get the research topic ─────────────────────────────────────────────────────

Console.ForegroundColor = ConsoleColor.Cyan;
Console.WriteLine("╔══════════════════════════════════════════╗");
Console.WriteLine("║       AI Research Agent (MAF + MEAI)     ║");
Console.WriteLine("╚══════════════════════════════════════════╝");
Console.ResetColor();
Console.WriteLine();

string topic;
if (args.Length > 0)
{
    topic = string.Join(' ', args);
}
else
{
    Console.Write("Enter a research topic: ");
    topic = Console.ReadLine()?.Trim() ?? string.Empty;
}

if (string.IsNullOrWhiteSpace(topic))
{
    Console.Error.WriteLine("No topic provided. Exiting.");
    return;
}

Console.WriteLine();
Console.ForegroundColor = ConsoleColor.Yellow;
Console.WriteLine($"Researching: {topic}");
Console.ResetColor();
Console.WriteLine(new string('─', 60));
Console.WriteLine();

// ── Run the agent ──────────────────────────────────────────────────────────────

var prompt = $"""
    You are a research assistant. Your task is to research the following topic 
    thoroughly and produce a well-organized summary.

    Topic: {topic}

    Instructions:
    1. Use the SearchWeb tool to search for information about this topic.
       Perform 2-3 different searches with varied queries to get broad coverage.
    2. As you find important information, use the SaveNote tool to record 
       key findings with descriptive titles.
    3. After gathering enough information, use the GetNotes tool to review 
       all your notes.
    4. Finally, write a comprehensive summary of your research findings,
       organized with clear sections and key takeaways.
    """;

